  ('promotion-53250add-moex-00178', 'promotion-53250add', 'promotion-53250add-moex-110-3082b5f1', 'sub-promotion-53250add-04', NULL, 'single_choice', '甲所有的部分土地長期供公眾通行使用，鄉公所並鋪設柏油道路，設置路燈及負責道路修繕。經 過數十年鄰地的聯外道路系統已相當發達，已少有公眾使用該既成道路。甲希望能使用供公眾使 用既成道路的土地，擬向行政法院提起訴訟恢復既成道路上土地得自由使用收益狀態。甲應提起 下列何種行政訴訟？', '["撤銷之訴", "一般給付之訴", "所有權返還之訴", "確認公法法律關係存否之訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00179', 'promotion-53250add', 'promotion-53250add-moex-110-3082b5f1', 'sub-promotion-53250add-04', NULL, 'single_choice', '甲市政府基於成本考量將該市所興建所有的焚化爐，委託乙公司運作經營。由於乙公司人員操作 焚化爐不當，釋放大量戴奧辛等有毒氣體致周邊居民吸入後產生健康的危害。請問受害居民應如 何求償，以下敘述何者正確？', '["甲市政府既已將焚化爐委託乙公司經營管理，受害居民僅能向乙公司行使民事侵權行為之損害 賠償，國家並無責任", "受害人民仍得以甲市政府為賠償義務機關提起國家賠償之訴，不論該焚化爐是否已經委託乙公 司經營管理", "受害人民對於其身體健康的損害，必須證明乙公司人員操作焚化爐有過失，始能請求國家賠償", "受害人民對於身體健康之損害，僅能擇一向乙公司提起民事損害賠償之訴，或以甲市政府為賠 償義務機關提起國家賠償之訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00180', 'promotion-53250add', 'promotion-53250add-moex-110-3082b5f1', 'sub-promotion-53250add-04', NULL, 'single_choice', '駕駛人於路邊停車格內停車，主管機關因該處地層下陷，緊急遂請拖吊業者將其車移至適當地點。 駕駛人事後發覺車輛因移置而受有損害。其可提出何種救濟？', '["向法院提起國家賠償", "向主管機關提起民事損害賠償", "向拖吊業者提起民事損害賠償", "向主管機關請求損失補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-6133703a-moex-00001', 'promotion-6133703a', 'promotion-6133703a-moex-114-916530c6', 'sub-promotion-6133703a-01', NULL, 'essay', '甲於 2025 年 7 月間偕同友人至海產熱炒餐廳聚餐，因故與鄰桌客人乙
發生口角，甲於聚餐結束返家後心有不甘，又騎機車回到前開餐廳門口
對乙叫囂，乙衝至門口取出攜帶於身上的開山刀對甲頸部氣管部位猛力
揮砍，甲先閃躲後持機車大鎖毆打乙作為反擊，乙因酒精影響氣力不濟，
在持刀揮空後，即因踩空倒地，此時甲仍逼近乙並對乙之頭部以機車大
鎖重擊一下，乙被毆打之後背對甲爬行欲離開現場，但甲仍在背後對乙
之頭部要害繼續以機車大鎖重擊 20 多下，導致乙因顱內嚴重出血當場
死亡。請問甲之刑責為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:06+00:00", "source_pdf_sha1": "12e62ec36437", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "124", "s": "0507", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "矯正"}'::jsonb, NULL),
  ('promotion-6133703a-moex-00002', 'promotion-6133703a', 'promotion-6133703a-moex-114-916530c6', 'sub-promotion-6133703a-01', NULL, 'essay', '甲男開小貨車行駛於馬路，見路上行人乙女外型亮麗，乃欲對乙強制性
交。甲先開車以相當高的速度將乙撞倒，再下車攙扶已經受嚴重傷害的
乙到自己車上，並對前來關心乙的其他路人宣稱自己將載乙就醫，路人
們因此放心離開。甲將乙放置於副駕駛座後，將乙載至附近人煙稀少的
田間道路，將乙下身衣物褪去欲對乙強制性交時，發現乙已經失去意識，
甲知道若放著乙不送醫，乙將因傷重死亡，但因害怕被發現，所以僅載
乙於鄉間道路繞行，未將乙送醫。其後甲被行經附近的員警發現攔停，
才發現於副駕駛座之乙，此時乙已因先前受到甲開車撞擊導致內臟大量
出血而死亡。事後經鑑定發現，如在乙遭甲撞傷時即能送醫救治，應不
會死亡。請問甲之刑責為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:06+00:00", "source_pdf_sha1": "12e62ec36437", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "124", "s": "0507", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "矯正"}'::jsonb, NULL),
  ('promotion-6133703a-moex-00003', 'promotion-6133703a', 'promotion-6133703a-moex-114-916530c6', 'sub-promotion-6133703a-01', NULL, 'essay', '電玩業者乙向 A市政府經濟發展局（以下簡稱經發局）申請核發營業登
記證，惟因申請之店面所在位置不符法規兩度遭退回，乙於是與市議會
多數黨之 B 黨團幹部即市議員甲約定：以新臺幣（以下同）100 萬元為
代價，並先交付 30 萬元現金給甲，由甲假借出席經發局員工家屬喪禮上
香之機會，約同樣在場之經發局長丙、承辦人丁同日晚間 10 點到 C 咖
啡廳召開「協調會」。丙、丁不得已出席甲所邀集之協調會，會中甲即以
杯葛經發局預算為藉口，要丙、丁以專案方式快速通過乙將要提出之申
請案。丙、丁迫於壓力承諾甲之請託內容。其後乙再以先前被退件的資料
原封不動提出第三次申請，A市經發局果然以專案方式核發營業登記證給
乙。事後乙也再依約交付70萬元給甲。請問甲之刑責為何？（25分）
12550', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:06+00:00", "source_pdf_sha1": "12e62ec36437", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "124", "s": "0507", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "矯正"}'::jsonb, NULL),
  ('promotion-6133703a-moex-00004', 'promotion-6133703a', 'promotion-6133703a-moex-114-916530c6', 'sub-promotion-6133703a-01', NULL, 'essay', '甲因配偶乙於家中自殺，欲搬家並自行將自住之透天房屋出售。甲因同
時積欠債務而欲將該房屋以較高價格出售，乃隱瞞上開兇宅之事實，連
同土地與建物以新臺幣（以下同）1,000 萬元出售給不知情的買家丙。丙
嗣後才發現原來所買為兇宅，實際行情應只有 700 萬元。丙嫌居住該屋
不吉利，也再將該屋出售，此時雖然丙誠實地於出售資訊中明示此一房
屋曾為兇宅的事實，但是仍吸引特別喜愛兇宅的房地產大亨丁，丁為能
早日取得所有權，明知為兇宅仍願意出價 1,100 萬元購買該屋，丙乃迅
速將房屋出售給丁並取得丁交付之1,100萬元對價。請問甲之刑責為何？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:06+00:00", "source_pdf_sha1": "12e62ec36437", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "124", "s": "0507", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "矯正"}'::jsonb, NULL),
  ('promotion-6133703a-moex-00005', 'promotion-6133703a', 'promotion-6133703a-moex-114-bdf4e0b8', 'sub-promotion-6133703a-02', NULL, 'essay', '心理測驗的「信度」與「效度」常被視為測驗品質的兩大核心指標。請
比較二者在理論基礎上的差異，並舉例說明在心理衡鑑中可能出現「高
信度但低效度」的情境。（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:06+00:00", "source_pdf_sha1": "9beaf032466f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "124", "s": "0605", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理測驗", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "矯正"}'::jsonb, NULL),
  ('promotion-6133703a-moex-00006', 'promotion-6133703a', 'promotion-6133703a-moex-114-bdf4e0b8', 'sub-promotion-6133703a-02', NULL, 'essay', '某研究者欲建立一份青少年社交焦慮量表，採用常模為「全國高中學
生」。請說明在解釋測驗分數時，使用此常模可能會遇到那些限制？若要
比較不同族群（例如性別、地區或文化背景），應如何處理常模的建立與
分數解釋問題？（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:06+00:00", "source_pdf_sha1": "9beaf032466f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "124", "s": "0605", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理測驗", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "矯正"}'::jsonb, NULL),
  ('promotion-6133703a-moex-00007', 'promotion-6133703a', 'promotion-6133703a-moex-114-bdf4e0b8', 'sub-promotion-6133703a-02', NULL, 'essay', '在進行心理測驗編製時，研究者除了關注題項難度與鑑別度外，還可能
考慮「測驗目的」與「受測情境」對題項設計的影響。請舉例說明不同
測驗目的下（如臨床診斷、教育選才），題項設計與項目分析可能的不同
取向。（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:06+00:00", "source_pdf_sha1": "9beaf032466f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "124", "s": "0605", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理測驗", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "矯正"}'::jsonb, NULL)
